+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { Column } from '~/column.ts';
+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+export type WindowBoundary =
+	| { type: 'unbounded preceding' }
+	| { type: 'current row' }
+	| { type: 'unbounded following' }
+	| { type: 'preceding'; value: number }
+	| { type: 'following'; value: number };
+
+export const unboundedPreceding: WindowBoundary = { type: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { type: 'current row' };
+export const unboundedFollowing: WindowBoundary = { type: 'unbounded following' };
+
+function assertOffset(name: string, value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowBoundary {
+	assertOffset('preceding', value);
+	return { type: 'preceding', value };
+}
+
+export function following(value: number): WindowBoundary {
+	assertOffset('following', value);
+	return { type: 'following', value };
+}
+
+export interface WindowFrame {
+	type: 'rows' | 'range';
+	from: WindowBoundary;
+	to: WindowBoundary;
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	switch (boundary.type) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	switch (boundary.type) {
+		case 'preceding': return sql.raw(`${boundary.value} preceding`);
+		case 'following': return sql.raw(`${boundary.value} following`);
+		default: return sql.raw(boundary.type);
+	}
+}
+
+export function windowSpecToSQL(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	if (spec.orderBy) parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	if (spec.frame) parts.push(sql`${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`);
+	return sql.join(parts, sql` `);
+}
+
+export function windowDefinitionToSQL(name: string, spec: WindowSpec): SQL {
+	return sql`${sql.identifier(name)} as (${windowSpecToSQL(spec)})`;
+}
+
+class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		if (typeof spec === 'string') return sql`${this.expression} over ${sql.identifier(spec)}`;
+		return sql`${this.expression} over (${windowSpecToSQL(spec)})`;
+	}
+}
+
+function fn<T>(name: string, ...args: SQLWrapper[]): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positional(name: string, value: number): SQLWrapper {
+	return sql.raw(String(value));
+}
+
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+}
+
+export function rowNumber(): WindowFunction<number> { return fn('row_number'); }
+export function rank(): WindowFunction<number> { return fn('rank'); }
+export function denseRank(): WindowFunction<number> { return fn('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return fn('ntile', positional('ntile', buckets)); }
+export function percentRank(): WindowFunction<number> { return fn('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return fn('cume_dist'); }
+
+type Value<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
